import { createServerClient, type CookieOptions } from '@supabase/ssr';
import { createClient as createSupabaseClient, type SupabaseClient, type SupabaseClientOptions } from '@supabase/supabase-js';
import { cookies } from 'next/headers';
import { Database } from './database.types';
import { getRequiredEnv } from '@lib/env';

// Criando o cliente Supabase para uso no lado do servidor
export const createClient = () => {
  const cookieStore = cookies();
  
  return createServerClient<Database>(
    getRequiredEnv('NEXT_PUBLIC_SUPABASE_URL'),
    getRequiredEnv('NEXT_PUBLIC_SUPABASE_ANON_KEY'),
    {
      cookies: {
        get(name: string) {
          return cookieStore.get(name)?.value;
        },
        set(name: string, value: string, options: CookieOptions) {
          try {
            cookieStore.set({ name, value, ...options });
          } catch {
            // The `set` method was called from a Server Component.
            // This can be ignored if you have middleware refreshing
            // user sessions.
          }
        },
        remove(name: string, options: CookieOptions) {
          try {
            cookieStore.set({ name, value: '', ...options });
          } catch {
            // The `remove` method was called from a Server Component.
            // This can be ignored if you have middleware refreshing
            // user sessions.
          }
        },
      },
    }
  );
};

// Cliente Supabase com a chave de serviço para operações administrativas
// Lazy initialization to avoid crashing at import time when env vars are missing
let _supabaseAdmin: SupabaseClient<Database> | null = null;

export function getSupabaseAdmin(): SupabaseClient<Database> {
  if (!_supabaseAdmin) {
    _supabaseAdmin = createSupabaseClient<Database>(
      getRequiredEnv('NEXT_PUBLIC_SUPABASE_URL'),
      getRequiredEnv('SUPABASE_SERVICE_ROLE_KEY'),
      {
        auth: {
          autoRefreshToken: false,
          persistSession: false,
        },
      }
    );
  }
  return _supabaseAdmin;
}

/** @deprecated Use getSupabaseAdmin() instead — lazy initialization prevents crashes when env vars are missing */
export const supabaseAdmin = new Proxy({} as SupabaseClient<Database>, {
  get(_target, prop) {
    return Reflect.get(getSupabaseAdmin(), prop);
  },
});

// Cria cliente Supabase usando Authorization do Request (para APIs)
export function getSupabaseForRequest(req: Request): SupabaseClient<Database> {
  const authHeader = (req.headers.get('authorization') || req.headers.get('Authorization'));

  // Se houver header de autorização, usa o cliente padrão (API externa/Service)
  if (authHeader) {
    const url = getRequiredEnv('NEXT_PUBLIC_SUPABASE_URL');
    const anonKey = getRequiredEnv('NEXT_PUBLIC_SUPABASE_ANON_KEY');
    const globalHeaders: Record<string, string> = { 'Authorization': authHeader };

    return createSupabaseClient<Database>(url, anonKey, {
      global: { headers: globalHeaders },
      auth: { persistSession: false, autoRefreshToken: false },
    } as SupabaseClientOptions<'public'>);
  }

  // Fallback: Se não houver header, tenta usar cookies (Browser/Dashboard)
  return createClient();
}

/**
 * Helper para acessar tabelas que não estão no schema Database gerado.
 * Usa type assertion controlado para tabelas conhecidas mas não tipadas.
 * 
 * @example
 * const { data } = await fromUntypedTable(supabase, 'avatars').select('*')
 */
export function fromUntypedTable<T = Record<string, unknown>>(
  client: SupabaseClient<Database>,
  tableName: string
) {
  return (client as unknown as Record<string, (...args: unknown[]) => unknown>).from(tableName) as ReturnType<SupabaseClient['from']> & {
    select: (columns?: string) => Promise<{ data: T[] | null; error: Error | null }>;
  };
}